import{_ as e,o as a,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"F02: 營業現金流與獲利品質 - finance-financial-analyst 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8064_東捷/20260429/F02_營業現金流與獲利品質_財務分析專家.md","filePath":"審計報告庫/財務審計/8064_東捷/20260429/F02_營業現金流與獲利品質_財務分析專家.md"}'),r={name:"審計報告庫/財務審計/8064_東捷/20260429/F02_營業現金流與獲利品質_財務分析專家.md"};function i(s,t,d,o,c,g){return a(),n("div",null,[...t[0]||(t[0]=[l(`<h1 id="f02-營業現金流與獲利品質-finance-financial-analyst-審計報告" tabindex="-1">F02: 營業現金流與獲利品質 - finance-financial-analyst 審計報告 <a class="header-anchor" href="#f02-營業現金流與獲利品質-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;F02: 營業現金流與獲利品質 - finance-financial-analyst 審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>營業活動現金流量 (CFO) 與稅後淨利之關係為何？獲利是否具備實質現金支撐？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：CFO/NI 從 -24.2%→391.4%，主因存貨應收回收非本業。FY2025 243.6%，含金量佳但賴週轉紅利。</li><li><strong>風險評級</strong>：中低，反轉則現金縮。</li><li><strong>數據時效</strong>：2025年報</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><h3 id="重點數據-單位-nt-千元" tabindex="-1">重點數據 (單位：NT$ 千元) <a class="header-anchor" href="#重點數據-單位-nt-千元" aria-label="Permalink to &quot;重點數據 (單位：NT$ 千元)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:center;">FY2022</th><th style="text-align:center;">FY2023</th><th style="text-align:center;">FY2024</th><th style="text-align:center;">FY2025</th></tr></thead><tbody><tr><td style="text-align:left;">營業收入</td><td style="text-align:center;">3,920,549</td><td style="text-align:center;">2,990,451</td><td style="text-align:center;">2,603,886</td><td style="text-align:center;">2,870,684</td></tr><tr><td style="text-align:left;">營收 YoY</td><td style="text-align:center;">—</td><td style="text-align:center;">-23.7%</td><td style="text-align:center;">-12.9%</td><td style="text-align:center;">+10.2%</td></tr><tr><td style="text-align:left;">稅後淨利 (NI)</td><td style="text-align:center;">377,824</td><td style="text-align:center;">185,612</td><td style="text-align:center;">173,907</td><td style="text-align:center;">266,821</td></tr><tr><td style="text-align:left;">CFO</td><td style="text-align:center;">-91,580</td><td style="text-align:center;">230,767</td><td style="text-align:center;">680,753</td><td style="text-align:center;">650,033</td></tr><tr><td style="text-align:left;"><strong>CFO/淨利比</strong></td><td style="text-align:center;"><strong>-24.2%</strong></td><td style="text-align:center;"><strong>124.3%</strong></td><td style="text-align:center;"><strong>391.4%</strong></td><td style="text-align:center;"><strong>243.6%</strong></td></tr><tr><td style="text-align:left;">折舊攤銷 (D&amp;A)</td><td style="text-align:center;">121,884</td><td style="text-align:center;">111,351</td><td style="text-align:center;">100,783</td><td style="text-align:center;">100,594</td></tr><tr><td style="text-align:left;">自由現金流 (FCF)</td><td style="text-align:center;">-111,779</td><td style="text-align:center;">224,713</td><td style="text-align:center;">650,318</td><td style="text-align:center;">592,941</td></tr><tr><td style="text-align:left;">應收帳款變動影響</td><td style="text-align:center;">+279,614</td><td style="text-align:center;">+12,770</td><td style="text-align:center;">+278,552</td><td style="text-align:center;">+236,162</td></tr><tr><td style="text-align:left;">存貨變動影響</td><td style="text-align:center;">-236,285</td><td style="text-align:center;">+567,861</td><td style="text-align:center;">+203,563</td><td style="text-align:center;">+330,625</td></tr></tbody></table><h3 id="診斷見解" tabindex="-1">診斷見解 <a class="header-anchor" href="#診斷見解" aria-label="Permalink to &quot;診斷見解&quot;">​</a></h3><p><strong>核心矛盾：現金流改善 ≠ 獲利改善。</strong> FY2024 的 391% CFO/NI 來自 FY2022 庫存爆增後的連續去化產生之報復性回收，非成長型現金創造。FY2025 營收回升 10.2%，CFO/NI 降至 243.6%，仍高於 120% 基準，但流動性紅利正遞減。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="子議題一-現金流對淨利比-cfo-ni-ratio-的四年軌跡解讀" tabindex="-1">子議題一：現金流對淨利比 (CFO/NI Ratio) 的四年軌跡解讀 <a class="header-anchor" href="#子議題一-現金流對淨利比-cfo-ni-ratio-的四年軌跡解讀" aria-label="Permalink to &quot;子議題一：現金流對淨利比 (CFO/NI Ratio) 的四年軌跡解讀&quot;">​</a></h3><ul><li><strong>核心重點</strong>：四年比值 -24.2% → 124.3% → 391.4% → 243.6%，FY2022 唯一負值。高峰 391.4% 來自 FY2022 庫存後連續三年去化（合計 +865.8M）及 AR 回收（+807.1M），屬一次性週轉紅利，非經常性盈餘轉化。</li></ul><h3 id="子議題二-非現金項目核實與折舊掩蓋診斷" tabindex="-1">子議題二：非現金項目核實與折舊掩蓋診斷 <a class="header-anchor" href="#子議題二-非現金項目核實與折舊掩蓋診斷" aria-label="Permalink to &quot;子議題二：非現金項目核實與折舊掩蓋診斷&quot;">​</a></h3><ul><li><strong>核心重點</strong>：D&amp;A 由 121.9M 降至 100.6M（-17.5%）。CFO+D&amp;A 四年分別為 +30.3M → +342.1M → +781.5M → +750.6M，FY2022 後營運本體已轉正，折舊非唯一救命繩。FY2025 NI 回升至 266.8M，D&amp;A 佔比降至 37.7%，緩解利潤虛胖疑慮。</li></ul><h3 id="子議題三-營運資金-ar-inventory-結構對獲利品質的定價權" tabindex="-1">子議題三：營運資金（AR/Inventory）結構對獲利品質的定價權 <a class="header-anchor" href="#子議題三-營運資金-ar-inventory-結構對獲利品質的定價權" aria-label="Permalink to &quot;子議題三：營運資金（AR/Inventory）結構對獲利品質的定價權&quot;">​</a></h3><ul><li><strong>核心重點</strong>：四年存貨去化合計 +865.8M，AR 回收合計 +807.1M。營收自 39.2 億降至 28.7 億（-26.8%），公司一度被迫現金優先於成長。FY2025 營收重回成長（+10.2%）且 CFO 維持高檔，惟須觀察 FY2026 營收續增是否重演「營收增→庫存增→現金縮」陷阱。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：成長陷阱重演</strong>。FY2025 營收成長 10.2%，但若客戶端（面板/半導體）產能擴張趨緩，東捷為爭取訂單可能再度接受更長的帳期或更大的備貨壓力，導致 AR/Inventory 重新膨脹。模擬試算：FY2025 的 CFO 650M 中，有 567M（AR 236M + 存貨 331M）來自週轉改善，剔除後本業 CFO 僅約 83M，對應 NI 266.8M，實質 CFO/NI 僅 31.1%（嚴重不足）。</li><li><strong>空頭風險二：折舊再投資壓力</strong>。設備製造業的 D&amp;A 雖為非現金項目，但公司需持續資本支出維持產能。FY2025 CapEx 僅 32.7M（far below D&amp;A 100.6M），長期設備折舊若未對應更新支出，產能可能老化影響接單能力。FY2022-FY2025 合計 CapEx 僅約 89M，對比合計 D&amp;A 434.6M，更新率僅 20.5%，暗示設備已過折舊年限但仍在使用，未來若需大規模汰換，FCF 將急縮。</li><li><strong>客戶集中度與應收風險</strong>：東捷前三大客戶多為面板/半導體大廠，單一客戶應收集中度高。若任一客戶發生財務困難，AR 回收停滯將直接擊穿 CFO。FY2025 AR 回收 236M 雖為正面，但也意味著集中度高達一定水位。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>年報 (2023-2025)</strong>：OK。直接擷取合併現金流量表與損益表原始數值。</li><li><strong>Web Search (cmoney/優分析)</strong>：OK。交叉比對確認營收與獲利總額一致。</li><li><strong>關鍵核對碼</strong>：<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FY2025: CFO 650,033 千元 | NI 266,821 千元 | 比值 243.6%</span></span>
<span class="line"><span>FY2024: CFO 680,753 千元 | NI 173,907 千元 | 比值 391.4%</span></span>
<span class="line"><span>FY2023: CFO 230,767 千元 | NI 185,612 千元 | 比值 124.3%</span></span>
<span class="line"><span>FY2022: CFO -91,580 千元 | NI 377,824 千元 | 比值 -24.2%</span></span></code></pre></div></li></ul><hr><p><strong>報告落地路徑</strong>：<code>/Users/kaipro/.openclaw/skills/NEW_Deep32Q/審計報告庫/8064_東捷/20260429/財務組/F02_營業現金流與獲利品質_審計報告.md</code></p>`,24)])])}const y=e(r,[["render",i]]);export{x as __pageData,y as default};
